#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 2400
#define H 1800

typedef struct { double x, y, z; } Vec;

Vec v(double x, double y, double z) {
    Vec r = {x, y, z};
    return r;
}

double dot(Vec a, Vec b) { return a.x*b.x + a.y*b.y + a.z*b.z; }
Vec sub(Vec a, Vec b) { return v(a.x-b.x, a.y-b.y, a.z-b.z); }
Vec add(Vec a, Vec b) { return v(a.x+b.x, a.y+b.y, a.z+b.z); }
Vec mul(Vec a, double s) { return v(a.x*s, a.y*s, a.z*s); }
Vec norm(Vec a) {
    double l = sqrt(dot(a,a));
    return v(a.x/l, a.y/l, a.z/l);
}

double clamp(double x) { return x < 0 ? 0 : (x > 255 ? 255 : x); }

int main() {
    FILE *f = fopen("reconstructed.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", W, H);

    // Camera: looking along -z, up = y
    double fov = 900.0;  // focal length in pixels
    double asp = (double)W / H;
    double cam_y = 1.5;  // camera height

    // Sphere
    Vec sp = v(0, 0.5, 0);  // sphere position
    double sr = 1.0;         // sphere radius

    // Light
    Vec lp = v(5, 5, 5);

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            double dx = (x - W/2.0) / fov;
            double dy = -(y - H/2.0) / fov;

            Vec dir = norm(v(dx, dy, -1));

            double r, g, b;
            int hit = 0;

            // Sphere intersection
            Vec oc = sub(v(0, cam_y, 0), sp);
            double a = dot(dir, dir);
            double bb = 2 * dot(oc, dir);
            double c = dot(oc, oc) - sr * sr;
            double disc = bb*bb - 4*a*c;

            if (disc > 0) {
                double t = (-bb - sqrt(disc)) / (2 * a);
                if (t > 0.001) {
                    Vec pt = add(v(0, cam_y, 0), mul(dir, t));
                    Vec n = norm(sub(pt, sp));
                    Vec L = norm(sub(lp, pt));
                    double diff = dot(n, L);
                    if (diff < 0) diff = 0;

                    Vec V = mul(dir, -1);
                    Vec Hv = norm(add(L, V));
                    double spec = dot(n, Hv);
                    if (spec < 0) spec = 0;
                    spec = pow(spec, 20);

                    // Red sphere
                    r = clamp((0.2 + 0.8 * diff) * 255 + spec * 200);
                    g = clamp((0.2 + 0.8 * diff) * 51 + spec * 40);
                    b = clamp((0.2 + 0.8 * diff) * 51 + spec * 40);
                    hit = 1;
                }
            }

            if (!hit && dir.y < 0) {
                // Ground plane at y = -0.5 (below camera)
                double t = -(cam_y - (-0.5)) / dir.y;
                if (t > 0) {
                    Vec pt = add(v(0, cam_y, 0), mul(dir, t));
                    int ix = (int)(floor(pt.x * 2.0) + 1000);
                    int iz = (int)(floor(pt.z * 2.0) + 1000);
                    double col = ((ix + iz) & 1) ? 152.0 : 67.0;

                    // Simple shadow
                    Vec L = norm(sub(lp, pt));
                    Vec oc2 = sub(pt, sp);
                    double sa = dot(L, L);
                    double sb = 2 * dot(oc2, L);
                    double sc = dot(oc2, oc2) - sr * sr;
                    double sd = sb*sb - 4*sa*sc;
                    if (sd > 0) {
                        double st = (-sb - sqrt(sd)) / (2 * sa);
                        if (st > 0.001) col *= 0.4;
                    }

                    r = g = b = clamp(col);
                    hit = 1;
                }
            }

            if (!hit) {
                // Sky
                double ndy = dir.y;
                double max_ndy = 0.7071067811865475;  // ndy at top center
                if (ndy > max_ndy) ndy = max_ndy;
                if (ndy < 0) ndy = 0;
                double t = ndy / max_ndy;
                r = clamp(191 - 45 * t);
                g = clamp(217 - 27 * t);
                b = 255;
            }

            fprintf(f, "%d %d %d\n", (int)r, (int)g, (int)b);
        }
    }

    fclose(f);
    return 0;
}
ENDCODE
